import React, { useState, useMemo, useEffect } from 'react';

const theme = {
  bg: '#0a0a0a', surface: '#111111', surfaceAlt: '#1a1a1a',
  border: '#2a2a2a', text: '#fafafa', muted: '#a1a1aa', dim: '#52525b',
  primary: '#8b5cf6', blue: '#38bdf8', green: '#a3e635',
  pink: '#f472b6', yellow: '#fbbf24', orange: '#fb923c', red: '#f87171',
};
const classColors = [theme.blue, theme.green, theme.pink];
const font = "'JetBrains Mono', monospace";

const X_raw = [[0.5, -1.2], [-0.3, 1.1], [0.8, -0.6]];
const y_raw = [0, 1, 2];

function softmax(z) {
  return z.map(row => {
    const mx = Math.max(...row);
    const exps = row.map(v => Math.exp(v - mx));
    const s = exps.reduce((a, b) => a + b, 0);
    return exps.map(e => e / s);
  });
}

function precompute(X, y, lr, maxIter) {
  const n = X.length;
  const C = Math.max(...y) + 1;
  const Xb = X.map(r => [1, ...r]);
  const M = Xb[0].length;
  const Y = y.map(l => { const o = new Array(C).fill(0); o[l] = 1; return o; });
  let B = Array.from({ length: M }, () => new Array(C).fill(0));

  const getProbs = (B) => {
    const z = Xb.map(x => {
      const row = new Array(C).fill(0);
      for (let j = 0; j < C; j++) for (let k = 0; k < M; k++) row[j] += x[k] * B[k][j];
      return row;
    });
    return softmax(z);
  };

  const snaps = [{
    coeffs: Array.from({ length: C }, () => Array.from({ length: M }, () => 0)),
    probs: getProbs(B), loss: null,
  }];

  for (let iter = 0; iter < maxIter; iter++) {
    const yPred = getProbs(B);
    let loss = 0;
    for (let i = 0; i < n; i++) loss -= Math.log(Math.max(yPred[i][y[i]], 1e-15));
    const diff = yPred.map((r, i) => r.map((v, j) => v - Y[i][j]));
    const grad = Array.from({ length: M }, (_, k) =>
      new Array(C).fill(0).map((_, j) => {
        let s = 0; for (let i = 0; i < n; i++) s += Xb[i][k] * diff[i][j]; return s;
      })
    );
    B = B.map((r, k) => r.map((v, j) => v - lr * grad[k][j]));
    snaps.push({
      coeffs: Array.from({ length: C }, (_, j) => Array.from({ length: M }, (_, k) => Math.round(B[k][j] * 10000) / 10000)),
      probs: getProbs(B),
      loss: Math.round(loss * 10000) / 10000,
    });
  }
  return snaps;
}

export default function App() {
  const [lr, setLr] = useState(0.01);
  const [iter, setIter] = useState(0);
  const [playing, setPlaying] = useState(false);
  const maxIter = 30;

  const snaps = useMemo(() => precompute(X_raw, y_raw, lr, maxIter), [lr]);

  useEffect(() => {
    if (!playing) return;
    const id = setInterval(() => {
      setIter(p => { if (p >= maxIter) { setPlaying(false); return p; } return p + 1; });
    }, 250);
    return () => clearInterval(id);
  }, [playing]);

  const cur = snaps[iter];
  const losses = snaps.slice(1, iter + 1).map(s => s.loss);
  const allLosses = snaps.slice(1).map(s => s.loss);
  const lossMin = allLosses.length ? Math.min(...allLosses) * 0.97 : 0;
  const lossMax = allLosses.length ? Math.max(...allLosses) * 1.02 : 4;

  const cW = 556, cH = 155, pL = 44, pR = 12, pT = 14, pB = 24;
  const pW = cW - pL - pR, pH = cH - pT - pB;
  const toX = i => pL + (i / maxIter) * pW;
  const toY = l => pT + pH - ((l - lossMin) / (lossMax - lossMin || 1)) * pH;

  const lossPath = losses.length > 0
    ? losses.map((l, i) => `${i === 0 ? 'M' : 'L'}${toX(i + 1).toFixed(1)},${toY(l).toFixed(1)}`).join(' ')
    : '';

  const reset = () => { setIter(0); setPlaying(false); };
  const togglePlay = () => { if (iter >= maxIter) setIter(0); setPlaying(p => !p); };

  const yTicks = 5;
  const tickVals = Array.from({ length: yTicks }, (_, i) => lossMin + (lossMax - lossMin) * i / (yTicks - 1));

  const insights = [
    'Initial state: all weights are zero, so softmax outputs uniform 1/3 probabilities for every class.',
    'Early iterations: gradients are large and loss drops quickly as the model starts separating classes.',
    iter >= 10 && iter < 20 ? 'Mid training: loss decrease slows down. The model is refining its decision boundaries.' :
    iter >= 20 ? 'Later iterations: loss converges. Increasing learning rate or iterations can push it further.' :
    'Each iteration computes softmax predictions, measures CE loss, then updates all class weight vectors.',
  ];
  const insightIdx = iter === 0 ? 0 : iter <= 5 ? 1 : 2;

  return (
    <div style={{ maxWidth: 600, margin: '0 auto', fontFamily: font, background: theme.bg, color: theme.text, padding: '14px 16px', minHeight: '100vh', boxSizing: 'border-box' }}>
      {/* Title */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
        <div style={{ fontSize: 17, fontWeight: 700 }}>Softmax Regression <span style={{ color: theme.primary }}>GD</span></div>
        <div style={{ display: 'flex', gap: 6 }}>
          <button onClick={togglePlay} style={{ background: theme.primary, color: '#fff', border: 'none', borderRadius: 6, padding: '5px 14px', cursor: 'pointer', fontFamily: font, fontSize: 12, fontWeight: 600 }}>
            {playing ? 'Pause' : (iter >= maxIter ? 'Replay' : 'Play')}
          </button>
          <button onClick={reset} style={{ background: theme.surfaceAlt, color: theme.muted, border: `1px solid ${theme.border}`, borderRadius: 6, padding: '5px 10px', cursor: 'pointer', fontFamily: font, fontSize: 12 }}>Reset</button>
        </div>
      </div>

      {/* Iteration slider */}
      <div style={{ background: theme.surface, borderRadius: 8, padding: '8px 12px', marginBottom: 6 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
          <span style={{ fontSize: 11, color: theme.muted }}>Iteration</span>
          <span style={{ fontSize: 13, fontWeight: 700, color: iter === 0 ? theme.dim : theme.yellow }}>{iter} <span style={{ color: theme.dim, fontWeight: 400 }}>/ {maxIter}</span></span>
        </div>
        <input type="range" min={0} max={maxIter} value={iter} onChange={e => { setIter(+e.target.value); setPlaying(false); }}
          style={{ width: '100%', accentColor: theme.yellow, height: 4 }} />
      </div>

      {/* LR slider */}
      <div style={{ background: theme.surface, borderRadius: 8, padding: '8px 12px', marginBottom: 10 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
          <span style={{ fontSize: 11, color: theme.muted }}>Learning Rate</span>
          <span style={{ fontSize: 13, fontWeight: 700, color: theme.orange }}>{lr.toFixed(3)}</span>
        </div>
        <input type="range" min={1} max={50} value={lr * 1000} onChange={e => { setLr(+e.target.value / 1000); setIter(0); setPlaying(false); }}
          style={{ width: '100%', accentColor: theme.orange, height: 4 }} />
      </div>

      {/* Loss Curve */}
      <div style={{ background: theme.surface, borderRadius: 10, padding: '10px 8px 6px', marginBottom: 10 }}>
        <div style={{ fontSize: 12, fontWeight: 600, color: theme.yellow, marginBottom: 4, paddingLeft: 6 }}>
          Cross Entropy Loss {cur.loss !== null && <span style={{ color: theme.text, fontWeight: 700, marginLeft: 8 }}>{cur.loss}</span>}
        </div>
        <svg width={cW} height={cH} style={{ display: 'block' }}>
          {/* Grid */}
          {tickVals.map((v, i) => (
            <g key={i}>
              <line x1={pL} x2={cW - pR} y1={toY(v)} y2={toY(v)} stroke={theme.border} strokeWidth={0.5} />
              <text x={pL - 4} y={toY(v) + 4} fill={theme.dim} fontSize={9} textAnchor="end" fontFamily={font}>{v.toFixed(1)}</text>
            </g>
          ))}
          {[0, 10, 20, 30].map(v => (
            <g key={v}>
              <line x1={toX(v)} x2={toX(v)} y1={pT} y2={cH - pB} stroke={theme.border} strokeWidth={0.5} />
              <text x={toX(v)} y={cH - pB + 14} fill={theme.dim} fontSize={9} textAnchor="middle" fontFamily={font}>{v}</text>
            </g>
          ))}
          {/* Faint full path */}
          {allLosses.length > 0 && (
            <path d={allLosses.map((l, i) => `${i === 0 ? 'M' : 'L'}${toX(i + 1).toFixed(1)},${toY(l).toFixed(1)}`).join(' ')}
              fill="none" stroke={theme.border} strokeWidth={1.5} strokeDasharray="3,3" />
          )}
          {/* Active path */}
          {lossPath && <path d={lossPath} fill="none" stroke={theme.yellow} strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round" />}
          {/* Current dot */}
          {losses.length > 0 && (
            <circle cx={toX(iter)} cy={toY(losses[losses.length - 1])} r={4.5} fill={theme.yellow} stroke={theme.bg} strokeWidth={2} />
          )}
          {iter === 0 && (
            <text x={cW / 2} y={cH / 2} fill={theme.dim} fontSize={12} textAnchor="middle" fontFamily={font}>Press Play or drag iteration slider</text>
          )}
        </svg>
      </div>

      {/* Predictions */}
      <div style={{ background: theme.surface, borderRadius: 10, padding: '10px 12px', marginBottom: 10 }}>
        <div style={{ fontSize: 12, fontWeight: 600, color: theme.muted, marginBottom: 8 }}>Predicted Probabilities per Sample</div>
        {X_raw.map((x, i) => {
          const probs = cur.probs[i];
          const pred = probs.indexOf(Math.max(...probs));
          const correct = pred === y_raw[i];
          return (
            <div key={i} style={{ marginBottom: i < 2 ? 8 : 0 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 3 }}>
                <span style={{ fontSize: 11, color: theme.muted }}>
                  x=[{x.join(', ')}] <span style={{ color: classColors[y_raw[i]], fontWeight: 600 }}>y={y_raw[i]}</span>
                </span>
                <span style={{ fontSize: 10, color: correct ? theme.green : theme.red, fontWeight: 600 }}>
                  pred={pred} {correct ? 'OK' : 'X'}
                </span>
              </div>
              <div style={{ display: 'flex', height: 18, borderRadius: 4, overflow: 'hidden', background: theme.bg }}>
                {probs.map((p, j) => (
                  <div key={j} style={{
                    width: `${(p * 100).toFixed(1)}%`, background: classColors[j],
                    opacity: j === y_raw[i] ? 1 : 0.35,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 9, fontWeight: 700, color: theme.bg,
                    transition: 'width 0.15s',
                    minWidth: p > 0.06 ? 0 : 0,
                  }}>
                    {p > 0.08 ? (p * 100).toFixed(0) + '%' : ''}
                  </div>
                ))}
              </div>
            </div>
          );
        })}
        <div style={{ display: 'flex', gap: 12, marginTop: 8, justifyContent: 'center' }}>
          {[0, 1, 2].map(c => (
            <div key={c} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 8, height: 8, borderRadius: 2, background: classColors[c] }} />
              <span style={{ fontSize: 10, color: theme.dim }}>Class {c}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Coefficients */}
      <div style={{ background: theme.surface, borderRadius: 10, padding: '10px 12px', marginBottom: 10 }}>
        <div style={{ fontSize: 12, fontWeight: 600, color: theme.muted, marginBottom: 6 }}>Coefficient Matrix (C x M) <span style={{ fontWeight: 400, fontSize: 10 }}>bias | w1 | w2</span></div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
          {cur.coeffs.map((row, c) => (
            <div key={c} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <span style={{ fontSize: 10, color: classColors[c], fontWeight: 700, width: 16 }}>C{c}</span>
              <div style={{ display: 'flex', gap: 3 }}>
                {row.map((v, j) => {
                  const mag = Math.min(Math.abs(v) * 8, 1);
                  const bg = v > 0 ? `rgba(163,230,53,${mag * 0.3})` : v < 0 ? `rgba(248,113,113,${mag * 0.3})` : theme.bg;
                  return (
                    <div key={j} style={{
                      background: bg, borderRadius: 4, padding: '2px 8px',
                      fontSize: 12, fontWeight: 600, fontFamily: font, color: theme.text,
                      minWidth: 58, textAlign: 'center', border: `1px solid ${theme.border}`,
                    }}>
                      {v.toFixed(4)}
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Key Insight */}
      <div style={{ background: theme.surfaceAlt, borderRadius: 8, padding: '8px 12px', fontSize: 11, color: theme.muted, borderLeft: `3px solid ${theme.primary}` }}>
        <span style={{ color: theme.primary, fontWeight: 700 }}>Key: </span>
        {insights[insightIdx]}
      </div>
    </div>
  );
}
